SELECT COUNT(*) > 0
FROM MEMBER
WHERE EMAIL = #{email}

SELECT MEMBER_ID AS "memberId", EMAIL AS "email", PASSWORD AS "password", NAME AS "name", NICKNAME AS "nickname", PROFILE_IMAGE AS "profileImage", SOCIAL_TYPE AS "socialType", ROLE AS "role", CREATE_DATE AS "createDate", LATEST_DATE AS "latestDate", STATUS AS "status" FROM MEMBER
AND UPPER(TRIM(STATUS)) = UPPER(TRIM(#{status}))
AND ROLE = #{role}
AND CREATE_DATE >= #{joinDateStart}
AND CREATE_DATE <= #{joinDateEnd}
AND LATEST_DATE IS NOT NULL AND SUBSTR(LATEST_DATE, 1, 10) >= #{lastLoginStart}
AND LATEST_DATE IS NOT NULL AND SUBSTR(LATEST_DATE, 1, 10) <= #{lastLoginEnd}
AND UPPER(TRIM(SOCIAL_TYPE)) = UPPER(TRIM(#{socialType}))
AND LOWER(EMAIL) LIKE '%' || LOWER(#{keyword}) || '%'
AND LOWER(NAME) LIKE '%' || LOWER(#{keyword}) || '%'
AND LOWER(NICKNAME) LIKE '%' || LOWER(#{keyword}) || '%'
ORDER BY CREATE_DATE DESC NULLS LAST

